export const IntegrationAuthType = {
  api_key: "api_key",
  oauth2: "oauth2",
  basic: "basic",
  bearer: "bearer",
  sftp: "sftp",
  none: "none",
} as const;

export type IntegrationStatus =
  (typeof IntegrationStatus)[keyof typeof IntegrationStatus];

export const IntegrationStatus = {
  disconnected: "disconnected",
  connected: "connected",
  pending: "pending",
  error: "error",
} as const;

export interface Integration {
  id: number;
  code: string;
  name: string;
  category: IntegrationCategory;
  authType: IntegrationAuthType;
  enabled: boolean;
  status: IntegrationStatus;
  lastSyncAt?: string | null;
  lastError?: string | null;
  hasCredentials: boolean;
}

export interface IntegrationsList {
  data: Integration[];
}

export type AssetKind = (typeof AssetKind)[keyof typeof AssetKind];

export const AssetKind = {
  audio: "audio",
  cover: "cover",
  image: "image",
  document: "document",
} as const;

export interface Asset {
  id: number;
  kind: AssetKind;
  objectPath: string;
  filename: string;
  mimeType: string;
  sizeBytes: number;
  sha256?: string | null;
  durationSeconds?: number | null;
  releaseId?: number | null;
  trackId?: number | null;
  artistId?: number | null;
  labelId?: number | null;
  uploadedBy?: number | null;
  createdAt: string;
  updatedAt: string;
}

export type AssetWithDownload = Asset & {
  /** Short-lived signed GET URL (TTL ~5 minutes) */
  downloadUrl: string;
};

export type PresignAssetBodyKind =
  (typeof PresignAssetBodyKind)[keyof typeof PresignAssetBodyKind];

export const PresignAssetBodyKind = {
  audio: "audio",
  cover: "cover",
  image: "image",
  document: "document",
} as const;

export interface PresignAssetBody {
  kind: PresignAssetBodyKind;
  /**
   * @minLength 1
   * @maxLength 255
   */
  filename: string;
  /**
   * @minLength 1
   * @maxLength 127
   */
  mimeType: string;
  /** @minimum 1 */
  sizeBytes: number;
  releaseId?: number | null;
  trackId?: number | null;
}

export interface PresignAssetResponse {
  uploadURL: string;
  objectPath: string;
  storageKey: string;
  expiresAt: string;
}

export type ConfirmAssetBodyKind =
  (typeof ConfirmAssetBodyKind)[keyof typeof ConfirmAssetBodyKind];

export const ConfirmAssetBodyKind = {
  audio: "audio",
  cover: "cover",
  image: "image",
  document: "document",
} as const;

export interface ConfirmAssetBody {
  storageKey: string;
  objectPath: string;
  kind: ConfirmAssetBodyKind;
  /**
   * @minLength 1
   * @maxLength 255
   */
  filename: string;
  /**
   * @minLength 1
   * @maxLength 127
   */
  mimeType: string;
  releaseId?: number | null;
  trackId?: number | null;
  /** If true, also writes the resulting URL to release.coverUrl / track.audioUrl. */
  attach?: boolean;
}

export interface Notification {
  id: number;
  userId: number;
  type: string;
  title: string;
  body: string;
  entityType?: string | null;
  entityId?: number | null;
  link?: string | null;
  readAt?: string | null;
  createdAt: string;
}

export interface PaginatedNotifications {
  data: Notification[];
  pagination: Pagination;
}

export interface UnreadNotificationCount {
  count: number;
}

